import React, { useEffect, useRef, useState } from 'react';
import { useNavigate } from 'react-router-dom';
import { useAuth } from '../../context/AuthContext';
import './Auth.css';

const Auth = ({ initialMode = 'login' }) => {
  const [mode, setMode] = useState(initialMode); // 'login' or 'signup'

  // login state
  const [loginEmail, setLoginEmail] = useState('');
  const [loginPassword, setLoginPassword] = useState('');
  const [loginErrors, setLoginErrors] = useState({});
  const [showLoginPassword, setShowLoginPassword] = useState(false);

  // signup state
  const [signupData, setSignupData] = useState({
    name: '',
    email: '',
    password: '',
    confirmPassword: ''
  });
  const [signupErrors, setSignupErrors] = useState({});
  const [showSignupPassword, setShowSignupPassword] = useState(false);
  const [showSignupConfirmPassword, setShowSignupConfirmPassword] = useState(false);
  const cardRef = useRef(null);

  const navigate = useNavigate();
  const { login, signup } = useAuth();

  useEffect(() => {
    setMode(initialMode === 'signup' ? 'signup' : 'login');
  }, [initialMode]);

  const validateLoginForm = () => {
    const newErrors = {};

    if (!loginEmail) {
      newErrors.email = 'Email is required';
    } else if (!/^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(loginEmail)) {
      newErrors.email = 'Invalid email format';
    }

    if (!loginPassword) {
      newErrors.password = 'Password is required';
    }

    return newErrors;
  };

  const handleLoginSubmit = (e) => {
    e.preventDefault();
    const newErrors = validateLoginForm();
    if (Object.keys(newErrors).length > 0) {
      setLoginErrors(newErrors);
      return;
    }

    const result = login(loginEmail, loginPassword);
    if (result.success) {
      navigate('/dashboard');
    } else {
      setLoginErrors({ general: result.message });
    }
  };

  const handleSignupChange = (e) => {
    const { name, value } = e.target;
    setSignupData(prev => ({
      ...prev,
      [name]: value
    }));
    if (signupErrors[name]) {
      setSignupErrors(prev => ({
        ...prev,
        [name]: ''
      }));
    }
  };

  const validateSignupForm = () => {
    const newErrors = {};

    if (!signupData.name.trim()) {
      newErrors.name = 'Name is required';
    } else if (signupData.name.trim().length < 2) {
      newErrors.name = 'Name must be at least 2 characters';
    }

    const emailRegex = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
    if (!signupData.email.trim()) {
      newErrors.email = 'Email is required';
    } else if (!emailRegex.test(signupData.email)) {
      newErrors.email = 'Please enter a valid email address';
    }

    const passwordRegex = /^(?=.*[a-z])(?=.*[A-Z])(?=.*\d).{6,}$/;
    if (!signupData.password) {
      newErrors.password = 'Password is required';
    } else if (!passwordRegex.test(signupData.password)) {
      newErrors.password = 'Password must be at least 6 characters with 1 uppercase, 1 lowercase, and 1 number';
    }

    if (!signupData.confirmPassword) {
      newErrors.confirmPassword = 'Please confirm your password';
    } else if (signupData.password !== signupData.confirmPassword) {
      newErrors.confirmPassword = 'Passwords do not match';
    }

    return newErrors;
  };

  const handleSignupSubmit = (e) => {
    e.preventDefault();
    const newErrors = validateSignupForm();
    if (Object.keys(newErrors).length > 0) {
      setSignupErrors(newErrors);
      return;
    }

    const result = signup(signupData.name, signupData.email, signupData.password);
    if (result.success) {
      navigate('/dashboard');
    } else {
      setSignupErrors({ general: result.message });
    }
  };

  const getPasswordStrength = (password) => {
    if (!password) return null;

    let strength = 0;
    if (password.length >= 6) strength++;
    if (/[a-z]/.test(password)) strength++;
    if (/[A-Z]/.test(password)) strength++;
    if (/[0-9]/.test(password)) strength++;
    if (/[^a-zA-Z0-9]/.test(password)) strength++;

    if (strength <= 2) return { text: 'Weak', color: '#ff4444' };
    if (strength <= 4) return { text: 'Medium', color: '#ffa700' };
    return { text: 'Strong', color: '#00C851' };
  };

  const passwordStrength = getPasswordStrength(signupData.password);

  // choose errors and helpers based on mode
  const errors = mode === 'login' ? loginErrors : signupErrors;

  const handleCardMouseMove = (e) => {
    const card = cardRef.current;
    if (!card) return;

    const rect = card.getBoundingClientRect();
    const x = e.clientX - rect.left;
    const y = e.clientY - rect.top;
    const px = x / rect.width;
    const py = y / rect.height;

    const rotateY = (px - 0.5) * 14;
    const rotateX = (0.5 - py) * 14;

    card.style.setProperty('--rx', `${rotateX.toFixed(2)}deg`);
    card.style.setProperty('--ry', `${rotateY.toFixed(2)}deg`);
    card.style.setProperty('--mx', `${(px * 100).toFixed(2)}%`);
    card.style.setProperty('--my', `${(py * 100).toFixed(2)}%`);
    card.style.setProperty('--ty', '-6px');
  };

  const handleCardMouseLeave = () => {
    const card = cardRef.current;
    if (!card) return;

    card.style.setProperty('--rx', '3deg');
    card.style.setProperty('--ry', '-3deg');
    card.style.setProperty('--mx', '50%');
    card.style.setProperty('--my', '0%');
    card.style.setProperty('--ty', '0px');
  };

  return (
    <div className="auth-container">
      <div
        ref={cardRef}
        className="auth-card"
        onMouseMove={handleCardMouseMove}
        onMouseLeave={handleCardMouseLeave}
      >
        <h2>{mode === 'login' ? 'Welcome Back!' : 'Create Account'}</h2>
        <p className="subtitle">
          {mode === 'login'
            ? 'Please login to your account'
            : 'Sign up to start tracking your BMI'}
        </p>

        {errors.general && (
          <div className="error-message">{errors.general}</div>
        )}

        <form onSubmit={mode === 'login' ? handleLoginSubmit : handleSignupSubmit}>
          {mode === 'signup' && (
            <div className="form-group">
              <label>Full Name</label>
              <input
                type="text"
                name="name"
                value={signupData.name}
                onChange={handleSignupChange}
                placeholder="Enter your full name"
                className={errors.name ? 'error' : ''}
              />
              {errors.name && <span className="error-text">{errors.name}</span>}
            </div>
          )}

          <div className="form-group">
            <label>Email Address</label>
            <input
              type="email"
              name="email"
              value={mode === 'login' ? loginEmail : signupData.email}
              onChange={(e) => {
                if (mode === 'login') {
                  setLoginEmail(e.target.value);
                  setLoginErrors({});
                } else {
                  handleSignupChange(e);
                }
              }}
              placeholder="Enter your email"
              className={errors.email ? 'error' : ''}
            />
            {errors.email && <span className="error-text">{errors.email}</span>}
          </div>

          <div className="form-group">
            <label>Password</label>
            <div className="password-field">
              <input
                type={
                  mode === 'login'
                    ? showLoginPassword
                      ? 'text'
                      : 'password'
                    : showSignupPassword
                    ? 'text'
                    : 'password'
                }
                name="password"
                value={
                  mode === 'login' ? loginPassword : signupData.password
                }
                onChange={(e) => {
                  if (mode === 'login') {
                    setLoginPassword(e.target.value);
                    setLoginErrors({});
                  } else {
                    handleSignupChange(e);
                  }
                }}
                placeholder={
                  mode === 'login' ? 'Enter your password' : 'Create a password'
                }
                className={errors.password ? 'error' : ''}
              />
              <button
                type="button"
                className="toggle-password"
                onClick={() => {
                  if (mode === 'login') {
                    setShowLoginPassword(!showLoginPassword);
                  } else {
                    setShowSignupPassword(!showSignupPassword);
                  }
                }}
              >
                {mode === 'login'
                  ? showLoginPassword
                    ? '👁️'
                    : '👁️‍🗨️'
                  : showSignupPassword
                  ? '👁️'
                  : '👁️‍🗨️'}
              </button>
            </div>

            {mode === 'signup' && signupData.password && (
              <div className="strength-indicator">
                <div
                  className="strength-bar"
                  style={{
                    width:
                      passwordStrength?.text === 'Weak'
                        ? '33%'
                        : passwordStrength?.text === 'Medium'
                        ? '66%'
                        : '100%',
                    backgroundColor: passwordStrength?.color
                  }}
                />
                <span style={{ color: passwordStrength?.color }}>
                  {passwordStrength?.text}
                </span>
              </div>
            )}

            {errors.password && <span className="error-text">{errors.password}</span>}
          </div>

          {mode === 'signup' && (
            <div className="form-group">
              <label>Confirm Password</label>
              <div className="password-field">
                <input
                  type={showSignupConfirmPassword ? 'text' : 'password'}
                  name="confirmPassword"
                  value={signupData.confirmPassword}
                  onChange={handleSignupChange}
                  placeholder="Confirm your password"
                  className={errors.confirmPassword ? 'error' : ''}
                />
                <button
                  type="button"
                  className="toggle-password"
                  onClick={() =>
                    setShowSignupConfirmPassword(!showSignupConfirmPassword)
                  }
                >
                  {showSignupConfirmPassword ? '👁️' : '👁️‍🗨️'}
                </button>
              </div>
              {errors.confirmPassword && (
                <span className="error-text">{errors.confirmPassword}</span>
              )}
            </div>
          )}

          <button type="submit" className="auth-btn">
            {mode === 'login' ? 'Login' : 'Sign Up'}
          </button>
        </form>

        <p className="toggle-link">
          {mode === 'login'
            ? "Don't have an account?"
            : 'Already have an account?'}{' '}
          <button
            onClick={() => {
              const next = mode === 'login' ? 'signup' : 'login';
              setMode(next);
              // clear state when switching
              setLoginEmail('');
              setLoginPassword('');
              setLoginErrors({});
              setSignupData({
                name: '',
                email: '',
                password: '',
                confirmPassword: ''
              });
              setSignupErrors({});
            }}
            className="link-btn"
          >
            {mode === 'login' ? 'Sign Up' : 'Login'}
          </button>
        </p>
      </div>
    </div>
  );
};

export default Auth;
